import { defineStore } from "pinia";
import { useWireFrameDocumentStore } from "./WireFrameDocumenStore";

const useEditionStore = defineStore({
  id: "EditionStore",
  state: () => {
    return {
      draggable: true,
      rotatable: false,
      warpable: false,
      scalable: false,
      resizable: true,
      selectable: true,
      snappable: false,
      zoomMultiplier: 1,
      actionPanel: "",
      previewMode: true,
      actualPage: "",
      targets: [] as (HTMLElement | SVGElement)[],
      flatPlanMode: false,
      spreadMode: false,
    };
  },
  actions: {
    goToFirstPage() {
      const wireFrameDocumentStore = useWireFrameDocumentStore();
      this.actualPage = wireFrameDocumentStore.document?.pages[0]?.name;
    },
    goToLastPage() {
      const wireFrameDocumentStore = useWireFrameDocumentStore();
      this.actualPage =
        wireFrameDocumentStore.document?.pages.slice(-1)[0]?.name;
    },
    goToPreviousPage() {
      const wireFrameDocumentStore = useWireFrameDocumentStore();
      const previousPageIndex =
        wireFrameDocumentStore.document?.pages.findIndex(
          (page) => page.name === this.actualPage
        ) - 1;
      if (previousPageIndex < 0) {
        return;
      }
      this.actualPage =
        wireFrameDocumentStore.document.pages[previousPageIndex].name;
    },

    goToNextPage() {
      const wireFrameDocumentStore = useWireFrameDocumentStore();
      const nextPageIndex =
        wireFrameDocumentStore.document?.pages.findIndex(
          (page) => page.name === this.actualPage
        ) + 1;
      if (nextPageIndex >= wireFrameDocumentStore.document.pages.length) {
        return;
      }
      this.actualPage =
        wireFrameDocumentStore.document.pages[nextPageIndex].name;
    },
  },
});

export { useEditionStore };
