import { defineStore } from "pinia";
import { useEditionStore } from "./EditionStore";
const useWireFrameDocumentStore = defineStore({
  id: "WireFrameDocumenStore",
  state: () => {
    return {
      document: {
        pages: [] as ActivePage[],
        name: "Active Document",
        properties: {
          backgroundColor: "#ffffff",
          width: 210,
          height: 290,
          measurementUnit: "mm",
        },
      },
      elements: [],
    };
  },
  getters: {
    getElementById: (state) => (id: string) => {
      const values = id.split("|");
      const elementId = values[0];
      const page = values[1];

      return state.elements[page].find((element) => element.id == elementId);
    },
    currentTarget: (state) => {
      const editionStore = useEditionStore();

      return () => {
        if (editionStore.targets.length == 0) return;
        return state.elements[editionStore.actualPage].find(
          (element) => element.id == editionStore.targets[0].id
        );
      };
    },
  },
  actions: {
    updateWireFrameDocument(wireFrameDocument: WireFrameDocument) {
      this.document = wireFrameDocument;
      const editionStore = useEditionStore();
      editionStore.goToFirstPage();
      wireFrameDocument.pages.forEach((page) => {
        this.elements[page.name] = page.elements;
      });
    },
    addBlock(newBlock: ElementInterface, pageName: string) {
      newBlock.properties = newBlock.properties ?? {};
      newBlock.id = newBlock.id.toString();
      newBlock.type = newBlock.type.toUpperCase();
      this.addElement(newBlock, pageName);
    },
    addPage(newPage: ActivePage) {
      const editionStore = useEditionStore();
      if (!newPage.pagePosition) {
        newPage.pagePosition =
          this.document.pages.reduce((maxPagePosition, page) => {
            return Math.max(maxPagePosition, page.pagePosition);
          }, 0) + 1;
      }
      let elements: ElementInterface[] = [];
      if (newPage.elements != undefined) {
        elements = newPage.elements;
      }
      this.elements[newPage.name] = [] ;

      elements.forEach((element) => {
        this.addElement(element, newPage.name);
      });
      this.document.pages.push(newPage);
      editionStore.actualPage = newPage.name;
    },
    addElement(newBlock: ElementInterface, pageName: string){
      newBlock.properties = newBlock.properties ?? {};
      newBlock.size = newBlock.size ?? {};
      newBlock.id = newBlock.id.toString();
      this.elements[pageName].push(newBlock);
    }
  },
});

export { useWireFrameDocumentStore };
